const allOrders = $('Sheets: Read All Orders').all().map(i => i.json);
const allWorkers = $('Sheets: Read All Workers').all().map(i => i.json);
const allPayments = $('Sheets: Read Payments').all().map(i => i.json);

const now = new Date();
const todayStr = now.toDateString();
const dateFormatted = now.toLocaleDateString('ru-RU', {
  day: '2-digit',
  month: '2-digit',
  year: 'numeric'
});

const todayOrders = allOrders.filter(o => {
  if (!o.created_at) return false;
  try {
    return new Date(o.created_at).toDateString() === todayStr;
  } catch (e) {
    return false;
  }
});

const total = todayOrders.length;
const published = todayOrders.filter(o => o.status === 'published').length;
const closed = todayOrders.filter(o => o.status === 'closed').length;
const cancelled = todayOrders.filter(o => o.status === 'cancelled').length;
const pending = todayOrders.filter(o => o.status === 'pending').length;

const todayPayments = allPayments.filter(p => {
  if (!p.paid_at) return false;
  try {
    return new Date(p.paid_at).toDateString() === todayStr && p.status === 'paid';
  } catch (e) {
    return false;
  }
});

const revenue = todayPayments.reduce((sum, p) => sum + (parseInt(p.amount) || 0), 0);

const conversion = total > 0
  ? Math.round((closed / total) * 100)
  : 0;

const closedToday = todayOrders.filter(o => o.status === 'closed');
const executorCounts = {};
closedToday.forEach(o => {
  if (o.executor_id) {
    executorCounts[o.executor_id] = (executorCounts[o.executor_id] || 0) + 1;
  }
});

let topWorkerId = '';
let topWorkerCount = 0;
for (const [id, count] of Object.entries(executorCounts)) {
  if (count > topWorkerCount) {
    topWorkerId = id;
    topWorkerCount = count;
  }
}

let topWorkerName = 'нет данных';
if (topWorkerId) {
  const worker = allWorkers.find(w => String(w.telegram_id) === String(topWorkerId));
  if (worker) {
    topWorkerName = `${worker.name || 'ID:' + topWorkerId} (${topWorkerCount} заказов, рейтинг ${worker.rating || '?'})`;
  }
}

const totalWorkers = allWorkers.length;
const activeVip = allWorkers.filter(w => {
  return (w.is_vip === 'TRUE' || w.is_vip === true) &&
    w.vip_expires_at && new Date(w.vip_expires_at) > now;
}).length;

const totalAllTime = allOrders.length;
const closedAllTime = allOrders.filter(o => o.status === 'closed').length;

return [{
  json: {
    date: dateFormatted,
    total,
    published,
    closed,
    cancelled,
    pending,
    revenue,
    conversion: conversion + '%',
    top_worker: topWorkerName,
    total_workers: totalWorkers,
    active_vip: activeVip,
    total_all_time: totalAllTime,
    closed_all_time: closedAllTime
  }
}];

const m = $('Calculate Metrics').first().json;

let text = `📊 Подряд PRO | Итоги ${m.date}\n`;
text += `━━━━━━━━━━━━━━━━━━━━━━\n\n`;

text += `📥 Новых заказов: ${m.total}\n`;
text += `⏳ В ожидании: ${m.pending}\n`;
text += `📤 Опубликовано: ${m.published}\n`;
text += `✅ Закрыто: ${m.closed}\n`;
text += `❌ Отменено: ${m.cancelled}\n\n`;

text += `💰 Выручка за день: ${m.revenue}р\n`;
text += `📈 Конверсия: ${m.conversion}\n\n`;

text += `🏆 Топ исполнитель: ${m.top_worker}\n\n`;

text += `━━━━━━━━━━━━━━━━━━━━━━\n`;
text += `📋 Общая статистика:\n`;
text += `👷 Исполнителей: ${m.total_workers}\n`;
text += `🌟 Активных VIP: ${m.active_vip}\n`;
text += `📦 Всего заказов: ${m.total_all_time}\n`;
text += `✅ Всего закрыто: ${m.closed_all_time}\n`;

return [{ json: { text } }];

